using SchoolEnterprise.Models.Domain; using SchoolEnterprise.Services; namespace SchoolEnterprise.Repositories; public class UserRepository(XmlStorageService storage) : BaseXmlRepository<AppUser>(storage){ protected override string FileName=>"users.xml"; public AppUser? GetById(int id)=>GetAll().FirstOrDefault(x=>x.UserId==id); public void Add(AppUser i){var a=GetAll();a.Add(i);SaveAll(a);} public void Update(AppUser i){var a=GetAll();var x=a.FindIndex(t=>t.UserId==i.UserId);if(x>=0){a[x]=i;SaveAll(a);}} public void Delete(int id){var a=GetAll();a.RemoveAll(x=>x.UserId==id);SaveAll(a);} }
